     1→import { getApi } from "@/shared/api/api";
     2→import { API_ROUTES } from "@/shared/config/api-routes";
     3→import { formatCentsToUSD } from "@/shared/lib/utils/price-formatter";
     4→import type {
     5→  SavedCryptoAddress,
     6→  SavedStripeMethod,
     7→  Wallet,
     8→  WalletTransactionsResponse,
     9→} from "@/shared/types/payment.types";
    10→import { cryptoAddressesService } from "./crypto-addresses.service";
    11→import { paypalMethodsService } from "./paypal-methods.service";
    12→import { stripeMethodsService } from "./stripe-methods.service";
    13→
    14→export interface WalletWithFormatted extends Wallet {
    15→  balanceFormatted: string;
    16→  usdtBalanceFormatted: string;
    17→}
    18→
    19→export interface SavedPaymentMethodMapped
    20→  extends Omit<SavedStripeMethod, "type"> {
    21→  type: "card" | "bank";
    22→}
    23→
    24→export interface WalletInfoResponse {
    25→  balance: number;
    26→  balanceDollars: number;
    27→  balanceFormatted: string;
    28→  usdtBalanceFormatted: string;
    29→  currency: string;
    30→  lastActivityAt?: string;
    31→  savedPaymentMethods: SavedPaymentMethodMapped[];
    32→  savedCryptoAddresses: SavedCryptoAddress[];
    33→}
    34→
    35→export interface TransactionFilters {
    36→  limit?: number;
    37→  skip?: number;
    38→}
    39→
    40→export interface WithdrawRequest {
    41→  amount: number;
    42→  paymentMethodId: string;
    43→  type: "fiat" | "crypto";
    44→}
    45→
    46→export interface WithdrawResponse {
    47→  transactionId: string;
    48→  status: string;
    49→  amount: number;
    50→  estimatedArrival?: string;
    51→}
    52→
    53→export interface CalculateWithdrawFeeRequest {
    54→  amount: number;
    55→  type: "fiat" | "crypto";
    56→}
    57→
    58→export interface CalculateWithdrawFeeResponse {
    59→  amount: number;
    60→  feeAmount: number;
    61→  totalAmount: number;
    62→  feePercentage: number;
    63→}
    64→
    65→export const walletService = {
    66→  async getWallet(): Promise<Wallet> {
    67→    const api = await getApi();
    68→    const { data } = await api.get<Wallet>(API_ROUTES.WALLET.GET);
    69→    return data;
    70→  },
    71→
    72→  async getTransactions(
    73→    filters?: TransactionFilters,
    74→  ): Promise<WalletTransactionsResponse> {
    75→    const api = await getApi();
    76→    const { data } = await api.get<WalletTransactionsResponse>(
    77→      API_ROUTES.WALLET.TRANSACTIONS,
    78→      {
    79→        params: {
    80→          limit: filters?.limit ?? 50,
    81→          skip: filters?.skip ?? 0,
    82→        },
    83→      },
    84→    );
    85→    return data;
    86→  },
    87→
    88→  async getWalletInfo(): Promise<WalletInfoResponse> {
    89→    const [wallet, savedPaymentMethods, savedCryptoAddresses] =
    90→      await Promise.all([
    91→        this.getWallet(),
    92→        stripeMethodsService.listMethods(),
    93→        cryptoAddressesService.listAddresses(),
    94→      ]);
    95→
    96→    return {
    97→      ...wallet,
    98→      balanceFormatted: formatCentsToUSD(wallet.balance),
    99→      usdtBalanceFormatted: `USDT ${formatCentsToUSD(wallet.balance)}`,
   100→      savedPaymentMethods: savedPaymentMethods.map((method) => ({
   101→        ...method,
   102→        type: method.type === "CARD" ? ("card" as const) : ("bank" as const),
   103→      })),
   104→      savedCryptoAddresses,
   105→    };
   106→  },
   107→
   108→  async getPayPalMethods() {
   109→    return paypalMethodsService.listMethods();
   110→  },
   111→
   112→  async withdraw(request: WithdrawRequest): Promise<WithdrawResponse> {
   113→    const api = await getApi();
   114→    const { data } = await api.post<WithdrawResponse>(
   115→      API_ROUTES.WALLET.WITHDRAW,
   116→      request,
   117→    );
   118→    return data;
   119→  },
   120→
   121→  async calculateWithdrawFee(
   122→    request: CalculateWithdrawFeeRequest,
   123→  ): Promise<CalculateWithdrawFeeResponse> {
   124→    const api = await getApi();
   125→    const { data } = await api.post<CalculateWithdrawFeeResponse>(
   126→      API_ROUTES.WALLET.CALCULATE_WITHDRAW_FEE,
   127→      request,
   128→    );
   129→    return data;
   130→  },
   131→};
