     1→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
     2→import { ApiKeys } from "../query-keys";
     3→import type {
     4→  CalculateWithdrawFeeRequest,
     5→  WithdrawRequest,
     6→} from "../services/wallet.service";
     7→import { walletService } from "../services/wallet.service";
     8→import { useDeleteStripeMethod } from "./use-stripe-methods";
     9→
    10→export function useWallet() {
    11→  return useQuery({
    12→    queryKey: ApiKeys.wallet(),
    13→    queryFn: () => walletService.getWallet(),
    14→  });
    15→}
    16→
    17→export function useWalletInfo() {
    18→  return useQuery({
    19→    queryKey: ApiKeys.wallet(),
    20→    queryFn: () => walletService.getWalletInfo(),
    21→  });
    22→}
    23→
    24→export function useWalletTransactions(params?: {
    25→  limit?: number;
    26→  skip?: number;
    27→}) {
    28→  return useQuery({
    29→    queryKey: ApiKeys.walletTransactions(params),
    30→    queryFn: () => walletService.getTransactions(params),
    31→  });
    32→}
    33→
    34→export function useDeletePaymentMethod() {
    35→  return useDeleteStripeMethod();
    36→}
    37→
    38→export function useWalletBalance() {
    39→  const { data: wallet, isLoading, error, refetch } = useWallet();
    40→
    41→  return {
    42→    balance: wallet?.balance ?? 0,
    43→    balanceDollars: wallet?.balanceDollars ?? 0,
    44→    currency: wallet?.currency ?? "USD",
    45→    isLoading,
    46→    error,
    47→    refetch,
    48→  };
    49→}
    50→
    51→export function useCheckSufficientBalance(requiredAmount: number) {
    52→  const { balance } = useWalletBalance();
    53→
    54→  const hasSufficientBalance = balance >= requiredAmount;
    55→  const shortfall = requiredAmount - balance;
    56→
    57→  return {
    58→    hasSufficientBalance,
    59→    currentBalance: balance,
    60→    requiredAmount,
    61→    shortfall: hasSufficientBalance ? 0 : shortfall,
    62→  };
    63→}
    64→
    65→export function useWithdraw() {
    66→  const queryClient = useQueryClient();
    67→
    68→  return useMutation({
    69→    mutationFn: (request: WithdrawRequest) => walletService.withdraw(request),
    70→    onSuccess: () => {
    71→      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
    72→      queryClient.invalidateQueries({ queryKey: ApiKeys.walletTransactions() });
    73→    },
    74→  });
    75→}
    76→
    77→export function useCalculateWithdrawFee(
    78→  request: CalculateWithdrawFeeRequest | null,
    79→) {
    80→  return useQuery({
    81→    queryKey: ApiKeys.withdrawFee(request),
    82→    queryFn: () => walletService.calculateWithdrawFee(request!),
    83→    enabled: !!request && request.amount > 0,
    84→  });
    85→}
