    31→const withdrawSchema = z.object({
    32→  amount: z
    33→    .string()
    34→    .min(1, "Amount is required")
    35→    .refine(
    36→      (val) => !Number.isNaN(Number(val)) && Number(val) > 0,
    37→      "Amount must be positive",
